fn check_k(n: usize, k: usize, nums: &Vec<i64>, sorted_nums: &Vec<i64>) -> bool {
    if k == 1 {
        // If k=1, each subarray has one element. No rearrangement possible within subarrays.
        // Only sortable if the array is already sorted.
        return nums == sorted_nums;
    }

    // The condition for sorting is that for every block of size k, the set of elements
    // within that block must match the set of elements in the corresponding block
    // of the sorted array. Since circular shifts allow arbitrary permutation within
    // the block, we only need to check if the elements are the same multiset.

    for i in 0..(n / k) {
        let start_original = i * k;
        let start_sorted = i * k;

        let original_block = &nums[start_original..(start_original + k)];
        let sorted_block = &sorted_nums[start_sorted..(start_sorted + k)];

        // To check if two blocks can be made equal by circular shift,
        // they must contain the same multiset of elements.

        // Since we are dealing with potentially large numbers, sorting the blocks 
        // and comparing them is the standard way to check multiset equality.
        let mut original_sorted = original_block.to_vec();
        original_sorted.sort();

        let mut sorted_block_sorted = sorted_block.to_vec();
        sorted_block_sorted.sort();

        if original_sorted != sorted_block_sorted {
            return false;
        }
    }

    // If n is not perfectly divisible by k, there's a remaining block, 
    // but the problem statement implies k is a divisor of n, so n % k == 0.
    // If k is a divisor, the loop above covers all n/k blocks of size k.

    true
}
